            aOrbiterK = ((aWandererD + RotL64(aScatter, 41U)) + RotL64(aCarry, 53U)) + 0x675DC4544820E490ULL;
            aOrbiterI = ((aWandererG + RotL64(aIngress, 52U)) + 0xE62D774E633905B9ULL) + aPhaseDOrbiterAssignSaltF[((aIndex + 27U)) & 31];
