            aOrbiterJ = (aWandererI + RotL64(aPrevious, 13U)) + 0x9586537D93859C7CULL;
            aOrbiterG = (aWandererH + RotL64(aCross, 39U)) + 0x87E4AE85F0C6D60EULL;
