            //
            aOrbiterF = (aOrbiterF + aOrbiterC) + 0x40543962E5290360ULL;
            aOrbiterG = ((aOrbiterG ^ aOrbiterF) ^ 0x6D4FAE5A19D6F415ULL) ^ aPhaseHOrbiterUpdateSaltB[((aIndex + 26U)) & 31];
